+//! Operator-facing feature flag registry commands.
+
+use clap::Subcommand;
+use mcp_agent_mail_core::Config;
+use mcp_agent_mail_core::flags::{self as core_flags, FlagRegistryError, FlagSnapshot};
+
+use crate::{CliError, CliResult, output};
