+#[must_use]
+pub fn flag_snapshots(config: &Config) -> Vec<FlagSnapshot> {
+    let mut flags = FLAG_REGISTRY
+        .iter()
+        .map(|flag| flag_snapshot(config, flag))
+        .collect::<Vec<_>>();
+    flags.sort_by(|left, right| {
+        left.subsystem
+            .cmp(&right.subsystem)
+            .then_with(|| left.name.cmp(&right.name))
+    });
+    flags
+}
